**具体实现**:
```typescript
// src/dashboard/server.ts
case 'control':
  const { action, iterationId } = command;

  switch (action) {
    case 'pause':
      // 暂停当前迭代
      await this.pauseIteration(iterationId);
      break;
    case 'resume':
      // 恢复迭代
      await this.resumeIteration(iterationId);
      break;
    case 'stop':
      // 停止迭代
      await this.stopIteration(iterationId);
      break;
    case 'rollback':
      // 回滚到指定迭代
      await this.rollbackToIteration(iterationId);
      break;
  }
  break;

async pauseIteration(iterationId: number) {
  // 1. 更新数据库状态
  await this.iterationService.updateStatus(iterationId, 'paused');

  // 2. 通知 AutoIterationEngine 暂停
  // 3. 广播 WebSocket 事件
  this.realtimeService.broadcast('iteration.paused', { iterationId });
}

async resumeIteration(iterationId: number) {
  await this.iterationService.updateStatus(iterationId, 'running');
  this.realtimeService.broadcast('iteration.resumed', { iterationId });
}

async stopIteration(iterationId: number) {
  await this.iterationService.updateStatus(iterationId, 'cancelled');
  this.realtimeService.broadcast('iteration.stopped', { iterationId });
}

async rollbackToIteration(iterationId: number) {
  const iteration = await this.iterationService.getById(iterationId);

  if (!iteration.commitHash) {
    throw new Error('No commit hash found for this iteration');
  }

  // 执行 git 回滚
  await exec(`git checkout ${iteration.commitHash}`);

  this.realtimeService.broadcast('iteration.rolledback', { 
    iterationId,
    commitHash: iteration.commitHash 
  });
}
```

