async rollback(iterationId: number): Promise<void> {
  const iteration = await this.findById(iterationId);

  if (!iteration || !iteration.commitHash) {
    throw new Error('Cannot rollback: invalid iteration');
  }

  // 执行 Git 回滚
  execSync(`git reset --hard ${iteration.commitHash}`, {
    cwd: this.projectPath
  });

  // 更新数据库状态
  await this.update(iterationId, { 
    status: IterationStatus.CANCELLED 
  });
}
