    public isOperational = true
  ) {
    super(message);
  }
}

// src/dashboard/middleware/error.middleware.ts
export function errorHandler(error: Error, req: any, reply: any) {
  if (error instanceof AppError) {
    reply.code(error.statusCode).send({
      success: false,
      error: {
        code: error.code,
        message: error.message
      }
    });
  } else {
    // 生产环境不暴露详细错误
    const isDev = process.env.NODE_ENV === 'development';
    reply.code(500).send({
      success: false,
      error: {
        code: 'INTERNAL_ERROR',
        message: isDev ? error.message : 'Internal server error'
      }
    });
  }
}
